"use client";

import { useState } from "react";

import PopularCategories from "@/app/components/user components/Store/PopularCategories";
import TopPhonesBanner from "@/app/components/user components/Store/TopPhones&Tablets";
import Filters from "@/app/components/user components/Store/Filters";

import { FaFilter, FaTimes } from "react-icons/fa";

export default function ProductsLayout({ children }) {
  const [filtersOpen, setFiltersOpen] = useState(false);

  return (
    <div>
      <TopPhonesBanner />
      <PopularCategories />

      {/* Mobile Filter Button */}
      <div className="md:hidden flex justify-end px-4 mt-3">
        <button
          onClick={() => setFiltersOpen(!filtersOpen)}
          className="flex items-center gap-2 bg-[#01A49E] text-white px-4 py-2 rounded-lg text-sm font-medium"
        >
          {filtersOpen ? <FaTimes /> : <FaFilter />}

          {filtersOpen ? "Close Filters" : "Open Filters"}
        </button>
      </div>

      {/* Main Layout */}
      <div className="max-w-7xl mx-auto bg-white mt-3 px-4 py-6 md:px-6 md:py-8 rounded-md">
        <div className="flex gap-6 md:gap-10 lg:gap-16">
          
          {/* Mobile Overlay */}
          {filtersOpen && (
            <div
              className="fixed inset-0 bg-black/40 z-40 md:hidden"
              onClick={() => setFiltersOpen(false)}
            />
          )}

          {/* Filters Sidebar */}
          <aside
            className={`
              fixed md:static top-0 left-0 z-50
              h-screen md:h-auto
              overflow-y-auto
              bg-white
              w-72 md:w-56 lg:w-64
              flex-shrink-0
              transition-transform duration-300 ease-in-out
              ${
                filtersOpen
                  ? "translate-x-0"
                  : "-translate-x-full"
              }
              md:translate-x-0
            `}
          >
            <div className="p-4 md:p-0">
              <Filters />
            </div>
          </aside>

          {/* Products */}
          <div className="flex-1 min-w-0">
            {children}
          </div>
        </div>
      </div>
    </div>
  );
}